/**
 * @class ListenOptions
 * @description Options to be used for listening.
 * @param {any} [options]
 * @param {String} [options.hotphrase] `hey_jibo` to listen for hey jibo before starting the listen. "" to start listening without waiting for hey jibo.
 * @param {Boolean} [options.speech_to_text] `true` to listen for cloud results, `false` otherwise.
 * @param {Boolean} [options.parseIncremental] `true` to parse incremental results, `false` otherwise.
 * @param {Boolean} [options.incremental] `true` to listen for incremental results, `flase` otherwise.
 * @param {Boolean} [options.forceGlobal] Force a non "hey jibo" (no hotphrase) listener to parse global and launch rules.
 * @param {String} [options.language=en-US] Language option for ASR recognition. Options are `en-US` (english), `ja-JP` (Japanese), `zh-CH` (Mandarin).
 * @memberof jibo.gl
 */

       /**
        * Listen for "Hey Jibo" before phrase.
        * @name jibo.gl.ListenOptions#hotphrase
        * @type {String}
        */

       /**
        * Listen for speech-to-text (cloud) results.
        * @name jibo.gl.ListenOptions#speech_to_text
        * @type {boolean}
        */

       /**
        * Parse the incremental results (with given grammar).
        * @name jibo.gl.ListenOptions#parseIncremental
        * @type {boolean}
        */

       /**
        * Listen for incremental results.
        * @name jibo.gl.ListenOptions#incremental
        * @type {boolean}
        */

       /**
        * Language option for ASR recognition.
        * @name jibo.gl.ListenOptions#language
        * @type {string}
        */

       /**
        * Verbose SSM and jibo logging within listener
        * @name jibo.gl.ListenOptions#verbose
        * @type {boolean}
        */

       /**
        * Expected duration of the utterance. 'short', 'medium', 'long', 'infinite'.
        * Infinite `expectedDuration` must be stopped manually.
        * @name jibo.gl.ListenOptions#expectedDuration
        * @type {string}
        */

